import { defineMvuDataStore } from '@util/mvu';
// 角色专属阶段枚举
const 可凌StageEnum = z.enum(['边界重构', '共生纠缠', '禁忌绽放']);
const 林珊珊StageEnum = z.enum(['阳光伪装', '嗅痕窃欲', '痴女觉醒']);
const 黄语情StageEnum = z.enum(['软萌依附', '昼夜双面', '反差崩坏']);
const 南枫StageEnum = z.enum(['琴房知音', '御姐私猎', '灵肉合一']);
const YesNoEnum = z.enum(['是', '否']);
const ItemSchema = z.object({
    描述: z.string().prefault('无描述'),
    数量: z.coerce.number().prefault(1),
});
const OutfitSchema = z.object({
    上装: z.string().prefault('待更新'),
    下装: z.string().prefault('待更新'),
    内衣: z.string().prefault('待更新'),
    袜子: z.string().prefault('待更新'),
    鞋子: z.string().prefault('待更新'),
    饰品: z.string().prefault('待更新'),
}).prefault({});
const BodyStatusSchema = z.object({
    神色: z.string().prefault('待更新'),
    乳房: z.string().prefault('待更新'),
    小穴: z.object({
        状态: z.string().prefault('待更新'),
        插入次数: z.coerce.number().prefault(0),
    }).prefault({}),
    肛门: z.object({
        状态: z.string().prefault('待更新'),
        插入次数: z.coerce.number().prefault(0),
    }).prefault({}),
}).prefault({});
const HeroineSchemaBase = z.object({
    阶段进度: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
    穿搭: OutfitSchema,
    突破事件: z.string().prefault('时机未到'),
    _隐秘身份: z.string().prefault('未知'),
    _表象身份: z.string().prefault('未知'),
    隐秘身份是否已暴露: YesNoEnum.prefault('否'),
    内心OS: z.string().prefault('...'),
    身体状态: BodyStatusSchema,
    角色专属属性: z.record(z.string(), z.string()).prefault({}),
});
export const Schema = z.object({
    世界: z.object({
        当前时间: z.string().prefault('17:15'),
        当前日期: z.string().prefault('2025年08月31日'),
        当前星期: z.string().prefault('星期日'),
        环境描述: z.string().prefault('待更新'),
        近期事务: z.string().prefault('待更新'),
        出场角色: z.array(z.string()).prefault([]),
    }).prefault({}),
    男主: z.object({
        内心OS: z.string().prefault('...'),
        物品栏: z.record(z.string(), ItemSchema).prefault({}),
    }).prefault({}),
    可凌: HeroineSchemaBase.extend({
        关系阶段: 可凌StageEnum.prefault('边界重构'),
    }).prefault({}),
    林珊珊: HeroineSchemaBase.extend({
        关系阶段: 林珊珊StageEnum.prefault('阳光伪装'),
    }).prefault({}),
    黄语情: HeroineSchemaBase.extend({
        关系阶段: 黄语情StageEnum.prefault('软萌依附'),
    }).prefault({}),
    南枫: HeroineSchemaBase.extend({
        关系阶段: 南枫StageEnum.prefault('琴房知音'),
    }).prefault({}),
});
export const useDataStore = defineMvuDataStore(Schema, {
    type: 'message',
    message_id: getCurrentMessageId(),
});
/** 四位女角色的名字列表，固定顺序 */
export const HEROINES = ['可凌', '林珊珊', '黄语情', '南枫'];
